import{_ as a,a as t}from"./chunks/webdav在win显示效果.BVTuSvY9.js";import{_ as o,o as n,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"WebDAV přístup k webu (Beta)","description":"","frontmatter":{},"headers":[],"relativePath":"cs-CZ/Safety/webdav-site-access.md","filePath":"cs-CZ/Safety/webdav-site-access.md","lastUpdated":1781962217000}'),s={name:"cs-CZ/Safety/webdav-site-access.md"};function d(r,e,p,u,h,b){return n(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="webdav-pristup-k-webu-beta" tabindex="-1">WebDAV přístup k webu (Beta) <a class="header-anchor" href="#webdav-pristup-k-webu-beta" aria-label="Permalink to &quot;WebDAV přístup k webu (Beta)&quot;">​</a></h1><p>Nastavení WebDAV v Bezpečnostních nastaveních zpřístupní váš web ImgBed jako WebDAV endpoint.</p><p>Po zapnutí můžete pomocí Windows, macOS, mobilních správců souborů nebo libovolného WebDAV kompatibilního klienta procházet, nahrávat, mazat a spravovat soubory ImgBed jako vzdálenou složku.</p><p>Toto je WebDAV přístup k samotnému webu. Liší se od WebDAV úložného kanálu v Nastavení nahrávání. Upload kanál ukládá soubory do externí WebDAV služby. Toto nastavení naopak umožní, aby váš web ImgBed poskytoval WebDAV přístup klientům.</p><h2 id="kde-nastavit" tabindex="-1">Kde nastavit <a class="header-anchor" href="#kde-nastavit" aria-label="Permalink to &quot;Kde nastavit&quot;">​</a></h2><p>Otevřete administraci a přejděte na:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; WebDAV</span></span></code></pre></div><p>Dostupná nastavení:</p><ul><li>Enable</li><li>Username</li><li>Password</li><li>Image loading mode</li><li>Default channel</li></ul><h2 id="co-tato-funkce-dela" tabindex="-1">Co tato funkce dělá <a class="header-anchor" href="#co-tato-funkce-dela" aria-label="Permalink to &quot;Co tato funkce dělá&quot;">​</a></h2><p>Po zapnutí WebDAV poskytuje ImgBed pevný přístupový URL:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/dav</span></span></code></pre></div><p>Tento URL použijte k připojení ke katalogu souborů ImgBed.</p><p>Vhodné použití:</p><ul><li>procházení souborů ImgBed přímo ze správce souborů v počítači.</li><li>přetažení obrázků do WebDAV složky pro upload.</li><li>organizace složek ImgBed z lokálního správce souborů.</li><li>použití WebDAV kompatibilního softwaru pro synchronizaci nebo správu obrázků.</li><li>přístup k obsahu ImgBed bez otevírání administrace.</li></ul><h2 id="nastaveni" tabindex="-1">Nastavení <a class="header-anchor" href="#nastaveni" aria-label="Permalink to &quot;Nastavení&quot;">​</a></h2><h3 id="enable" tabindex="-1">Enable <a class="header-anchor" href="#enable" aria-label="Permalink to &quot;Enable&quot;">​</a></h3><p>Zapne WebDAV endpoint.</p><p>Když je vypnutý, klienti se přes WebDAV nepřipojí.</p><h3 id="username-a-password" tabindex="-1">Username a Password <a class="header-anchor" href="#username-a-password" aria-label="Permalink to &quot;Username a Password&quot;">​</a></h3><p>Tyto údaje používají WebDAV klienti při připojení.</p><p>Použijte samostatné uživatelské jméno a heslo pro WebDAV. Nepoužívejte znovu administrátorské heslo ani heslo pro upload.</p><p>Pokud je uživatelské jméno nebo heslo prázdné, WebDAV klienti se nepřipojí správně.</p><h3 id="image-loading-mode" tabindex="-1">Image Loading Mode <a class="header-anchor" href="#image-loading-mode" aria-label="Permalink to &quot;Image Loading Mode&quot;">​</a></h3><p>Image loading mode určuje, jaký URL obrázku WebDAV klienti preferují při čtení.</p><p>Běžné volby:</p><table tabindex="0"><thead><tr><th>Režim</th><th>Popis</th></tr></thead><tbody><tr><td>Smart loading</td><td>ImgBed vybere podle kontextu. Doporučeno pro běžné použití.</td></tr><tr><td>Original</td><td>Preferuje původní obrázky.</td></tr><tr><td>Thumbnail</td><td>Preferuje miniatury. Užitečné pro rychlý náhled.</td></tr></tbody></table><p>Pokud si nejste jistí, ponechte <code>Smart loading</code>.</p><h3 id="default-channel" tabindex="-1">Default Channel <a class="header-anchor" href="#default-channel" aria-label="Permalink to &quot;Default Channel&quot;">​</a></h3><p>Výchozí kanál se používá pro WebDAV uploady.</p><p>Když z Windows nebo jiného klienta kopírujete soubory do WebDAV adresáře, ImgBed je nahraje přes vybraný výchozí upload kanál.</p><p>Pokud není vybraný výchozí kanál, procházení může fungovat, ale uploady mohou selhat.</p><h2 id="pristup-pres-webdav-ve-windows-11" tabindex="-1">Přístup přes WebDAV ve Windows 11 <a class="header-anchor" href="#pristup-pres-webdav-ve-windows-11" aria-label="Permalink to &quot;Přístup přes WebDAV ve Windows 11&quot;">​</a></h2><p>Windows 11 umí WebDAV přidat jako síťové umístění.</p><ol><li>Otevřete <code>This PC</code>.</li><li>Vyberte <code>Add a network location</code>.</li><li>Zadejte <code>https://your-domain.com/dav</code>.</li><li>Po výzvě zadejte uživatelské jméno a heslo WebDAV.</li><li>Dokončete průvodce. WebDAV adresář pak půjde otevřít v File Explorer.</li></ol><p><img src="'+a+'" alt="Přidání WebDAV ve Windows 11" loading="lazy"></p><p>Po přidání se WebDAV adresář zobrazí v Průzkumníku souborů Windows. Soubory můžete otevírat, kopírovat a spravovat jako běžnou složku.</p><p><img src="'+t+'" alt="WebDAV ve Windows" loading="lazy"></p><h2 id="podporovane-operace" tabindex="-1">Podporované operace <a class="header-anchor" href="#podporovane-operace" aria-label="Permalink to &quot;Podporované operace&quot;">​</a></h2><p>Po úspěšném WebDAV připojení obvykle můžete:</p><ul><li>zobrazovat soubory a složky.</li><li>nahrávat soubory.</li><li>vytvářet složky.</li><li>přejmenovávat soubory nebo složky.</li><li>přesouvat soubory.</li><li>mazat soubory.</li></ul><p>WebDAV je vhodný pro každodenní přístup a menší správu souborů. Pro velké přesuny, hromadné mazání nebo složitou organizaci použijte administraci.</p><h2 id="login-device-management" tabindex="-1">Login Device Management <a class="header-anchor" href="#login-device-management" aria-label="Permalink to &quot;Login Device Management&quot;">​</a></h2><p>Úspěšná WebDAV připojení se zobrazují také na kartě WebDAV v Login Device Management.</p><p>Můžete tam kontrolovat WebDAV klienty a podle potřeby vynutit stará zařízení offline.</p><p>Pokud změníte WebDAV uživatelské jméno nebo heslo, staří klienti se musí přihlásit znovu.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="windows-stale-zada-uzivatelske-jmeno-a-heslo" tabindex="-1">Windows stále žádá uživatelské jméno a heslo <a class="header-anchor" href="#windows-stale-zada-uzivatelske-jmeno-a-heslo" aria-label="Permalink to &quot;Windows stále žádá uživatelské jméno a heslo&quot;">​</a></h3><p>Zkontrolujte:</p><ul><li>URL je <code>https://your-domain.com/dav</code>.</li><li>Uživatelské jméno a heslo odpovídají nastavení WebDAV.</li><li>WebDAV je zapnutý.</li><li>Web je dostupný přes HTTPS.</li></ul><h3 id="prochazeni-funguje-ale-upload-ne" tabindex="-1">Procházení funguje, ale upload ne <a class="header-anchor" href="#prochazeni-funguje-ale-upload-ne" aria-label="Permalink to &quot;Procházení funguje, ale upload ne&quot;">​</a></h3><p>Zkontrolujte <code>Default channel</code>.</p><p>WebDAV uploady potřebují výchozí upload kanál. Pokud chybí, je vypnutý nebo špatně nastavený, uploady mohou selhat.</p><h3 id="rychlost-pristupu-je-nestabilni" tabindex="-1">Rychlost přístupu je nestabilní <a class="header-anchor" href="#rychlost-pristupu-je-nestabilni" aria-label="Permalink to &quot;Rychlost přístupu je nestabilní&quot;">​</a></h3><p>Výkon WebDAV závisí na klientovi, síti, počtu souborů a výchozím upload kanálu.</p><p>Pokud má adresář mnoho souborů, uspořádejte je do složek místo uložení příliš mnoha souborů na jednom místě.</p><h2 id="bezpecnostni-doporuceni" tabindex="-1">Bezpečnostní doporučení <a class="header-anchor" href="#bezpecnostni-doporuceni" aria-label="Permalink to &quot;Bezpečnostní doporučení&quot;">​</a></h2><ul><li>Pro WebDAV přístup používejte HTTPS.</li><li>Nastavte silné heslo.</li><li>Nesdílejte WebDAV heslo s nedůvěryhodnými lidmi.</li><li>WebDAV vypněte, když ho nepoužíváte.</li><li>Pravidelně čistěte nepoužívaná WebDAV zařízení v Login Device Management.</li></ul><h2 id="velikost-souboru-pri-webdav-uploadu" tabindex="-1">Velikost souboru při WebDAV uploadu <a class="header-anchor" href="#velikost-souboru-pri-webdav-uploadu" aria-label="Permalink to &quot;Velikost souboru při WebDAV uploadu&quot;">​</a></h2><p>WebDAV klienti nepoužívají prohlížečový chunk upload ze stránky uploadu. Pro soubory nad doporučené limity níže použijte webovou upload stránku.</p><table tabindex="0"><thead><tr><th>Výchozí upload kanál</th><th style="text-align:right;">Doporučený limit jednoho WebDAV souboru</th></tr></thead><tbody><tr><td>Telegram</td><td style="text-align:right;">20 MB</td></tr><tr><td>Discord</td><td style="text-align:right;">10 MB</td></tr><tr><td>Cloudflare R2</td><td style="text-align:right;">30 MB</td></tr><tr><td>S3</td><td style="text-align:right;">30 MB</td></tr><tr><td>GitHub Releases</td><td style="text-align:right;">64 MB</td></tr><tr><td>GitLab Packages</td><td style="text-align:right;">64 MB</td></tr><tr><td>Hugging Face</td><td style="text-align:right;">20 MB</td></tr><tr><td>OneDrive</td><td style="text-align:right;">30 MB</td></tr><tr><td>Google Drive</td><td style="text-align:right;">30 MB</td></tr><tr><td>Dropbox</td><td style="text-align:right;">30 MB</td></tr><tr><td>Yandex Disk</td><td style="text-align:right;">30 MB</td></tr><tr><td>pCloud</td><td style="text-align:right;">30 MB</td></tr><tr><td>WebDAV</td><td style="text-align:right;">64 MB</td></tr></tbody></table>',61)])])}const k=o(s,[["render",d]]);export{m as __pageData,k as default};
